sys_script_include.script:
function GetRecentEvaluatorErrors(nMinutes)
{
	nMinutes = GetIntegerValue(nMinutes);
	if (nMinutes < 1)
	{
		return [];
	}

	var aErrors = [];
	var grLog = new GlideRecord('syslog');

	var strQuery = GetRecentEvaluatorErrorsQuery(nMinutes);
	grLog.addEncodedQuery(strQuery);

	GlideRecordQuery(grLog,true);
	while (grLog.next())
	{
		aErrors.push(Clone(grLog));
	}
	return aErrors;
}
